const data = $input.first().json;
const caseId = 'RC-' + Date.now();
const timestamp = new Date().toISOString();
const fecha = new Date().toLocaleDateString('es-CO', {timeZone: 'America/Bogota'});

return [{
  json: {
    caseId,
    timestamp,
    fecha,
    nombres: data['Nombres Completos']?.trim() || '',
    apellidos: data['Apellidos Completos']?.trim() || '',
    tipoDocumento: data['Tipo de Documento'] || '',
    numeroDocumento: data['Número de Documento']?.trim() || '',
    lugarExpedicion: data['Lugar de Expedición']?.trim() || '',
    direccion: data['Dirección de Domicilio']?.trim() || '',
    departamento: data['Departamento']?.trim() || '',
    ciudad: data['Ciudad']?.trim() || '',
    email: data['Correo Electrónico']?.trim().toLowerCase() || '',
    celular: data['Número de Celular']?.trim() || '',
    nombreCompleto: (data['Nombres Completos'] + ' ' + data['Apellidos Completos']).trim(),
    estado: 'Nuevo - Paso 1: Diagnóstico Pendiente',
    etapa: 1,
    valorPaso1: 70000,
    valorPaso2: 280000,
    valorPaso3: 350000
  }
}];

