const aiOutput = $input.first().json.output || $input.first().json.text || '';
const client = $('Validar y Formatear').first().json;
let diagnosis;
try {
  const match = aiOutput.match(/\{[\s\S]*\}/);
  diagnosis = match ? JSON.parse(match[0]) : { mensajeBienvenida: aiOutput };
} catch(e) {
  diagnosis = { mensajeBienvenida: aiOutput };
}

const emailHtml = `
<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background: #1a3a5c; padding: 20px; text-align: center;">
    <h1 style="color: white; margin: 0;">Recuperación Crediticia</h1>
    <p style="color: #a0c4ff; margin: 5px 0;">Ekinoxis Financial Services</p>
  </div>
  <div style="padding: 30px; background: #f9f9f9;">
    <p>Estimado/a <strong>${client.nombres}</strong>,</p>
    <p>${diagnosis.mensajeBienvenida || 'Su solicitud ha sido recibida exitosamente.'}</p>
    <div style="background: white; border-left: 4px solid #1a3a5c; padding: 15px; margin: 20px 0;">
      <h3 style="color: #1a3a5c; margin-top: 0;">Número de Caso: ${client.caseId}</h3>
      <p><strong>Paso 1 — Diagnóstico Crediticio:</strong> $70,000 COP</p>
      <p>${diagnosis.descripcionPaso1 || 'Análisis completo de su historial crediticio.'}</p>
    </div>
    <p><strong>Tiempo estimado:</strong> ${diagnosis.tiempoEstimado || '3-5 días hábiles'}</p>
    <p><strong>Nota importante:</strong> ${diagnosis.informacionImportante || ''}</p>
    <div style="background: #e8f4fd; padding: 15px; border-radius: 5px;">
      <h4 style="color: #1a3a5c;">Próximos Pasos:</h4>
      <ol>
        <li>Espere confirmación de pago del Paso 1</li>
        <li>Recibirá su diagnóstico completo</li>
        <li>Se procederá con las etapas siguientes</li>
      </ol>
    </div>
  </div>
  <div style="background: #1a3a5c; padding: 15px; text-align: center;">
    <p style="color: #a0c4ff; margin: 0; font-size: 12px;">© Ekinoxis | Para consultas responda este correo</p>
  </div>
</div>`;

return [{json: { ...client, diagnosis, emailHtml }}];
